import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw['topLevelPackages']:
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for key in all_keys:
    proj, tfm, pkg = key
    bv = b.get(key, 'N/A')
    av = a.get(key, 'N/A')
    if bv != av:
        changes.append((proj, tfm, pkg, bv, av))
    else:
        unchanged.append((proj, tfm, pkg, bv))

print('=== CHANGES ===')
if changes:
    print(f\"{'Project':<15} {'TFM':<8} {'Package':<50} {'Before':<10} {'After':<10}\")
    for proj, tfm, pkg, bv, av in changes:
        print(f'{proj:<15} {tfm:<8} {pkg:<50} {bv:<10} {av:<10}')
else:
    print('No changes detected.')

print()
print('=== UNCHANGED ===')
print(f\"{'Project':<15} {'TFM':<8} {'Package':<50} {'Version':<10}\")
for proj, tfm, pkg, v in unchanged:
    print(f'{proj:<15} {tfm:<8} {pkg:<50} {v:<10}')
"
